"use strict";(self.webpackChunkengine_docs=self.webpackChunkengine_docs||[]).push([[64514],{99330:(e,n,t)=>{t.r(n),t.d(n,{assets:()=>l,contentTitle:()=>i,default:()=>h,frontMatter:()=>o,metadata:()=>s,toc:()=>c});var a=t(74848),r=t(28453);const o={},i=void 0,s={id:"Tutorials/UserInterface/Core/Chart",title:"Chart",description:'window.open("https://thatopen.github.io/engine_ui-components/examples/Chart")} >Go Full Screen',source:"@site/docs/Tutorials/UserInterface/Core/Chart.mdx",sourceDirName:"Tutorials/UserInterface/Core",slug:"/Tutorials/UserInterface/Core/Chart",permalink:"/Tutorials/UserInterface/Core/Chart",draft:!1,unlisted:!1,tags:[],version:"current",frontMatter:{},sidebar:"tutorialSidebar",previous:{title:"UserInterface",permalink:"/Tutorials/UserInterface/"},next:{title:"Component",permalink:"/Tutorials/UserInterface/Core/Component"}},l={},c=[{value:"A Picture is Worth a Thousand BIM Elements \ud83d\udcca",id:"a-picture-is-worth-a-thousand-bim-elements-",level:3},{value:"\ud83c\udfa8 Initializing the Library and Creating Your First Chart",id:"-initializing-the-library-and-creating-your-first-chart",level:3},{value:"\ud83c\udfb2 Preparing the Data",id:"-preparing-the-data",level:3},{value:"\u2699\ufe0f Building the Controls",id:"\ufe0f-building-the-controls",level:3},{value:"\ud83d\udcca Creating the Chart Dashboard",id:"-creating-the-chart-dashboard",level:3},{value:"\ud83d\udd0c Wiring Controls to Charts",id:"-wiring-controls-to-charts",level:3},{value:"\ud83e\udd13 Putting Everything Together",id:"-putting-everything-together",level:3}];function d(e){const n={a:"a",admonition:"admonition",code:"code",h3:"h3",hr:"hr",p:"p",pre:"pre",...(0,r.R)(),...e.components};return(0,a.jsxs)(a.Fragment,{children:[(0,a.jsxs)("div",{style:{position:"relative"},children:[(0,a.jsx)("iframe",{src:"https://thatopen.github.io/engine_ui-components/examples/Chart"}),(0,a.jsx)("button",{class:"full-screen-btn",onClick:()=>window.open("https://thatopen.github.io/engine_ui-components/examples/Chart"),children:"Go Full Screen"})]}),"\n",(0,a.jsx)(n.admonition,{title:"Source",type:"info",children:(0,a.jsxs)(n.p,{children:["Copying and pasting? We've got you covered! You can find the full source code of this tutorial ",(0,a.jsx)(n.a,{href:"https://github.com/ThatOpen/engine_ui-components/blob/main/packages/core/src/components/Chart/example.ts",children:"here"}),"."]})}),"\n",(0,a.jsx)(n.h3,{id:"a-picture-is-worth-a-thousand-bim-elements-",children:"A Picture is Worth a Thousand BIM Elements \ud83d\udcca"}),"\n",(0,a.jsx)(n.hr,{}),"\n",(0,a.jsx)(n.p,{children:"BIM application developers who want to present model data \u2014 element counts by category, cost breakdowns, schedule progress \u2014 as charts have to wire up a third-party charting library themselves, reconciling its data format with BIM data structures and styling it to match the rest of the UI.\nThe Chart web component wraps a full charting engine behind a single custom element that accepts BIM-shaped data directly and exposes visual properties as HTML attributes, so charts stay consistent with the rest of the component library without any extra configuration.\nThis tutorial covers preparing datasets in the expected shape for cartesian charts (bar, line, radar), part-of-a-whole charts (pie, doughnut, polar area), and scatter/bubble charts; creating a responsive CSS grid dashboard with eight chart types side by side; configuring shared visual properties (index axis, point style, line fill, smoothing, stacking, label visibility, colors, transparent background); wiring a shared legend that toggles datasets across all charts at once; listening for click events on individual chart sections; and toggling a loading state across the whole dashboard.\nBy the end, you'll have a fully interactive eight-chart dashboard driven by shared controls, where changing any visual setting updates every chart simultaneously."}),"\n",(0,a.jsx)(n.h3,{id:"-initializing-the-library-and-creating-your-first-chart",children:"\ud83c\udfa8 Initializing the Library and Creating Your First Chart"}),"\n",(0,a.jsx)(n.hr,{}),"\n",(0,a.jsxs)(n.p,{children:["Just like any other component in our library, the first step is to initialize ",(0,a.jsx)(n.code,{children:"@thatopen/ui"})," in your app. You only need to do this once to unlock all the awesome Web Components we offer. It's super straightforward:"]}),"\n",(0,a.jsx)(n.pre,{children:(0,a.jsx)(n.code,{className:"language-js",children:'// You have to import from "@thatopen/ui"\nimport * as BUI from "../..";\n\nBUI.Manager.init();\n'})}),"\n",(0,a.jsx)(n.h3,{id:"-preparing-the-data",children:"\ud83c\udfb2 Preparing the Data"}),"\n",(0,a.jsx)(n.hr,{}),"\n",(0,a.jsxs)(n.p,{children:["A dashboard of charts is only as good as the data behind it. To keep the tutorial\nself-contained we use two small helpers that produce random numbers: one for the\ncartesian charts (bar, line, radar) where negative values make sense, and one for\nthe part-of-a-whole charts (pie, doughnut, polarArea) where every slice must be\npositive. The helpers return data in the shape ",(0,a.jsx)(n.code,{children:"bim-chart"})," expects \u2014 a list of\nlabels and one or more named datasets."]}),"\n",(0,a.jsx)(n.pre,{children:(0,a.jsx)(n.code,{className:"language-js",children:'const signedValue = () => Math.round(Math.random() * 180 - 90);\nconst positiveValue = () => Math.round(Math.random() * 90 + 10);\n\nconst categoryLabels = ["Walls", "Slabs", "Columns", "Windows", "Doors"];\n\nconst cartesianData = () => ({\n  labels: categoryLabels,\n  datasets: {\n    "Series A": categoryLabels.map(() => ({ value: signedValue() })),\n    "Series B": categoryLabels.map(() => ({ value: signedValue() })),\n  },\n});\n\nconst positiveData = () => ({\n  labels: categoryLabels,\n  datasets: {\n    "Series A": categoryLabels.map(() => ({ value: positiveValue() })),\n  },\n});\n\nconst scatterData = (radius: number) => {\n  const points: BUI.ChartInputValues[] = [];\n  const labels: string[] = [];\n  for (let i = 0; i < 12; i++) {\n    labels.push(`Point ${i + 1}`);\n    points.push({\n      x: Math.round(Math.random() * 100),\n      y: Math.round(Math.random() * 100),\n      r: radius,\n    });\n  }\n  return { labels, datasets: { "Series A": points } };\n};\n'})}),"\n",(0,a.jsx)(n.h3,{id:"\ufe0f-building-the-controls",children:"\u2699\ufe0f Building the Controls"}),"\n",(0,a.jsx)(n.hr,{}),"\n",(0,a.jsx)(n.p,{children:"The chart component exposes a handful of visual properties. To showcase them\ninteractively we'll wire them up to a small panel of BUI controls \u2014 dropdowns for\nindex axis, point shape and fill direction, sliders for radius, and checkboxes for\nstacking and label visibility. Each control updates every chart in the dashboard\nat once so you can compare how the same setting affects different chart types."}),"\n",(0,a.jsx)(n.pre,{children:(0,a.jsx)(n.code,{className:"language-js",children:'const panel = BUI.Component.create(() => {\n  const indexAxisDropdown = document.createElement("bim-dropdown");\n  indexAxisDropdown.label = "Index Axis";\n  for (const a of ["x", "y"]) {\n    const option = document.createElement("bim-option");\n    option.value = a;\n    option.label = a.toUpperCase();\n    indexAxisDropdown.appendChild(option);\n  }\n\n  const pointStyleDropdown = document.createElement("bim-dropdown");\n  pointStyleDropdown.label = "Point Style";\n  const styles = ["circle", "cross", "crossRot", "dash", "line", "rect", "rectRounded", "rectRot", "triangle", "star"];\n  for (const style of styles) {\n    const option = document.createElement("bim-option");\n    option.value = style;\n    option.label = style[0].toUpperCase() + style.slice(1);\n    pointStyleDropdown.appendChild(option);\n  }\n\n  const lineFillDropdown = document.createElement("bim-dropdown");\n  lineFillDropdown.label = "Line Fill";\n  for (const fill of ["origin", "start", "end", "false"]) {\n    const option = document.createElement("bim-option");\n    option.value = fill;\n    option.label = fill[0].toUpperCase() + fill.slice(1);\n    lineFillDropdown.appendChild(option);\n  }\n\n  const pointRadiusInput = document.createElement("bim-number-input");\n  pointRadiusInput.label = "Point Radius";\n\n  const bubbleRadiusInput = document.createElement("bim-number-input");\n  bubbleRadiusInput.label = "Bubble Radius";\n\n  const xStackedCheck = document.createElement("bim-checkbox");\n  xStackedCheck.label = "X Stacked";\n\n  const yStackedCheck = document.createElement("bim-checkbox");\n  yStackedCheck.label = "Y Stacked";\n\n  const transparentBackgroundCheck = document.createElement("bim-checkbox");\n  transparentBackgroundCheck.label = "Transparent Background";\n\n  const lineSmoothingCheckbox = document.createElement("bim-checkbox");\n  lineSmoothingCheckbox.label = "Line Smoothing";\n\n  const displayLabelsCheckbox = document.createElement("bim-checkbox");\n  displayLabelsCheckbox.label = "Display Labels";\n\n  const dataLabelsColorInput = document.createElement("bim-color-input");\n  dataLabelsColorInput.label = "Data Labels Color";\n\n  const borderColorInput = document.createElement("bim-color-input");\n  borderColorInput.label = "Border Color";\n\n  const toggleLoadingBtn = document.createElement("bim-button");\n  toggleLoadingBtn.label = "Toggle Loading";\n'})}),"\n",(0,a.jsx)(n.h3,{id:"-creating-the-chart-dashboard",children:"\ud83d\udcca Creating the Chart Dashboard"}),"\n",(0,a.jsx)(n.hr,{}),"\n",(0,a.jsxs)(n.p,{children:["The dashboard is a single CSS grid that auto-fits the available width: each\nchart lives in its own sized card so rows and columns stay aligned no matter\nhow many charts we include. Every ",(0,a.jsx)(n.code,{children:"bim-chart"})," is created with the same starting\nconfiguration \u2014 a transparent background, white data labels, and no border \u2014\nso the charts feel like part of a single dashboard rather than nine independent\nwidgets. Pie-family charts get the positive-only data helper so their slices\nalways make sense; cartesian charts get the signed helper."]}),"\n",(0,a.jsx)(n.pre,{children:(0,a.jsx)(n.code,{className:"language-js",children:'const chartTypes: { type: BUI.Chart["type"]; title: string; positive: boolean }[] = [\n    { type: "bar",       title: "Bar",       positive: false },\n    { type: "line",      title: "Line",      positive: false },\n    { type: "radar",     title: "Radar",     positive: false },\n    { type: "pie",       title: "Pie",       positive: true  },\n    { type: "doughnut",  title: "Doughnut",  positive: true  },\n    { type: "polarArea", title: "Polar Area",positive: true  },\n    { type: "scatter",   title: "Scatter",   positive: true  },\n    { type: "bubble",    title: "Bubble",    positive: true  },\n  ];\n\n  const charts: BUI.Chart[] = [];\n  let chartLegend: BUI.ChartLegend | undefined;\n  let currentBubbleRadius = 10;\n\n  const onChartCreated = (e: Element | undefined, type: BUI.Chart["type"], positive: boolean) => {\n    if (!e) return;\n    const chart = e as BUI.Chart;\n    chart.inputData =\n      type === "scatter" || type === "bubble"\n        ? scatterData(currentBubbleRadius)\n        : positive ? positiveData() : cartesianData();\n    chart.label = "";\n    chart.indexAxis = "x";\n    chart.linePointStyle = "circle";\n    chart.lineFill = "origin";\n    chart.pointRadius = 4;\n    chart.xStacked = false;\n    chart.yStacked = false;\n    chart.transparentBackground = true;\n    chart.dataLabelsColor = "#ffffff";\n    chart.borderColor = "#00000000";\n    chart.smoothLine = true;\n    chart.displayLabels = true;\n    charts.push(chart);\n  };\n\n  const onChartLegendCreated = (e?: Element) => {\n    if (!e) return;\n    chartLegend = e as BUI.ChartLegend;\n    chartLegend.charts = charts;\n  };\n\n  const onSectionClick = (data: CustomEvent<BUI.DataClickDetail>) => {\n    console.log(data.detail);\n  };\n'})}),"\n",(0,a.jsx)(n.h3,{id:"-wiring-controls-to-charts",children:"\ud83d\udd0c Wiring Controls to Charts"}),"\n",(0,a.jsx)(n.hr,{}),"\n",(0,a.jsxs)(n.p,{children:["Each control broadcasts its change to every chart in the dashboard, so tweaking\none value updates the whole grid at once. This makes it easy to see how a single\nsetting affects every chart type side by side. We also listen for ",(0,a.jsx)(n.code,{children:"sectionclick"}),"\non each chart, which fires whenever the user clicks a bar, slice or point and\ngives you the underlying data \u2014 perfect for drill-down UIs."]}),"\n",(0,a.jsx)(n.pre,{children:(0,a.jsx)(n.code,{className:"language-js",children:'indexAxisDropdown.addEventListener("change", () => {\n    charts.forEach((c) => { c.indexAxis = indexAxisDropdown.value[0]; });\n    BUI.ContextMenu.removeMenus();\n  });\n\n  xStackedCheck.addEventListener("change", () => {\n    charts.forEach((c) => { c.xStacked = xStackedCheck.value; });\n  });\n\n  yStackedCheck.addEventListener("change", () => {\n    charts.forEach((c) => { c.yStacked = yStackedCheck.value; });\n  });\n\n  pointStyleDropdown.addEventListener("change", () => {\n    charts.forEach((c) => { c.linePointStyle = pointStyleDropdown.value[0] as BUI.LinePointStyleType; });\n    BUI.ContextMenu.removeMenus();\n  });\n\n  pointRadiusInput.addEventListener("change", () => {\n    charts.forEach((c) => { c.pointRadius = pointRadiusInput.value; });\n  });\n\n  lineFillDropdown.addEventListener("change", () => {\n    charts.forEach((c) => { c.lineFill = lineFillDropdown.value[0] as BUI.LineFillType; });\n    BUI.ContextMenu.removeMenus();\n  });\n\n  transparentBackgroundCheck.addEventListener("change", () => {\n    charts.forEach((c) => { c.transparentBackground = transparentBackgroundCheck.value; });\n  });\n\n  dataLabelsColorInput.addEventListener("input", () => {\n    charts.forEach((c) => { c.dataLabelsColor = dataLabelsColorInput.value.color; });\n  });\n\n  lineSmoothingCheckbox.addEventListener("change", () => {\n    charts.forEach((c) => { c.smoothLine = lineSmoothingCheckbox.value; });\n  });\n\n  displayLabelsCheckbox.addEventListener("change", () => {\n    charts.forEach((c) => { c.displayLabels = displayLabelsCheckbox.value; });\n  });\n\n  borderColorInput.addEventListener("input", () => {\n    charts.forEach((c) => { c.borderColor = borderColorInput.value.color; });\n  });\n\n  toggleLoadingBtn.addEventListener("click", () => {\n    charts.forEach((c) => { c.loading = !c.loading; });\n  });\n\n  bubbleRadiusInput.addEventListener("change", () => {\n    currentBubbleRadius = bubbleRadiusInput.value;\n    charts.forEach((c) => {\n      if (c.type === "bubble" || c.type === "scatter") {\n        c.inputData = scatterData(currentBubbleRadius);\n      }\n    });\n  });\n\n  // Set initial control values\n  indexAxisDropdown.value = ["x"];\n  pointStyleDropdown.value = ["circle"];\n  lineFillDropdown.value = ["origin"];\n  pointRadiusInput.value = 4;\n  bubbleRadiusInput.value = 10;\n  xStackedCheck.checked = false;\n  yStackedCheck.checked = false;\n  transparentBackgroundCheck.checked = true;\n  dataLabelsColorInput.value = { color: "#ffffff" };\n  borderColorInput.value = { color: "#00000000" };\n  lineSmoothingCheckbox.checked = true;\n  displayLabelsCheckbox.checked = true;\n'})}),"\n",(0,a.jsx)(n.h3,{id:"-putting-everything-together",children:"\ud83e\udd13 Putting Everything Together"}),"\n",(0,a.jsx)(n.hr,{}),"\n",(0,a.jsxs)(n.p,{children:["The final layout is a two-column flex: on the left a scrollable CSS grid\nthat auto-fits chart cards so the dashboard reflows gracefully on narrow\nscreens, and on the right a fixed-width sidebar with the shared ",(0,a.jsx)(n.code,{children:"bim-chart-legend"}),"\n(clicking an entry toggles that dataset across every chart at once) and the\ncontrol panel. Every chart card has a fixed height, so rows stay aligned\nregardless of the chart type."]}),"\n",(0,a.jsx)(n.pre,{children:(0,a.jsx)(n.code,{className:"language-js",children:'const chartCards = chartTypes.map(({ type, title, positive }) => BUI.html`\n    <div style="\n      display: flex;\n      flex-direction: column;\n      background: var(--bim-ui_bg-contrast-10);\n      border-radius: 0.5rem;\n      padding: 0.75rem;\n      min-height: 18rem;\n    ">\n      <div style="\n        font-size: 0.8rem;\n        font-weight: 600;\n        color: var(--bim-ui_main-contrast);\n        text-transform: uppercase;\n        letter-spacing: 0.05em;\n        margin-bottom: 0.5rem;\n        opacity: 0.7;\n      ">${title}</div>\n      <div style="flex: 1; min-height: 0;">\n        <bim-chart\n          type="${type}"\n          @sectionclick=${onSectionClick}\n          ${BUI.ref((e) => onChartCreated(e, type, positive))}\n        ></bim-chart>\n      </div>\n    </div>\n  `);\n\n  return BUI.html`\n    <bim-panel label="Charts" style="height: 100%; width: 100%;">\n      <div style="\n        display: flex;\n        flex-direction: row;\n        gap: 1rem;\n        width: 100%;\n        height: 100%;\n        padding: 1rem;\n        box-sizing: border-box;\n      ">\n        \x3c!-- Chart grid (left) --\x3e\n        <div style="flex: 1; min-width: 0; overflow: auto;">\n          <div style="\n            display: grid;\n            grid-template-columns: repeat(auto-fit, minmax(20rem, 1fr));\n            gap: 1rem;\n          ">\n            ${chartCards}\n          </div>\n        </div>\n\n        \x3c!-- Sidebar (right) --\x3e\n        <div style="\n          width: 22rem;\n          display: flex;\n          flex-direction: column;\n          gap: 1rem;\n          overflow: auto;\n        ">\n          <bim-panel-section label="\ud83d\udd11 Legend" style="flex: 0 0 auto;">\n            <bim-chart-legend ${BUI.ref(onChartLegendCreated)}></bim-chart-legend>\n          </bim-panel-section>\n\n          <bim-panel-section label="\u2699\ufe0f Controls" style="flex: 1 1 auto;">\n            <div style="display: flex; flex-direction: column; gap: 0.75rem;">\n              ${indexAxisDropdown}\n              ${pointStyleDropdown}\n              ${lineFillDropdown}\n              ${pointRadiusInput}\n              ${bubbleRadiusInput}\n              ${xStackedCheck}\n              ${yStackedCheck}\n              ${transparentBackgroundCheck}\n              ${lineSmoothingCheckbox}\n              ${displayLabelsCheckbox}\n              ${dataLabelsColorInput}\n              ${borderColorInput}\n              ${toggleLoadingBtn}\n            </div>\n          </bim-panel-section>\n        </div>\n      </div>\n    </bim-panel>\n  `;\n});\n\ndocument.body.append(panel);\n'})}),"\n",(0,a.jsx)(n.p,{children:"And that's it! A single CSS grid, a unified legend, and one set of controls\ndrive the entire dashboard \u2014 change any setting and every chart updates at once.\nFrom here, plug in real data from your BIM model and you have an interactive\nanalytics view with barely any code. Happy coding! \ud83d\ude80"})]})}function h(e={}){const{wrapper:n}={...(0,r.R)(),...e.components};return n?(0,a.jsx)(n,{...e,children:(0,a.jsx)(d,{...e})}):d(e)}},28453:(e,n,t)=>{t.d(n,{R:()=>i,x:()=>s});var a=t(96540);const r={},o=a.createContext(r);function i(e){const n=a.useContext(o);return a.useMemo((function(){return"function"==typeof e?e(n):{...n,...e}}),[n,e])}function s(e){let n;return n=e.disableParentContext?"function"==typeof e.components?e.components(r):e.components||r:i(e.components),a.createElement(o.Provider,{value:n},e.children)}}}]);